static int initialize_cuda(int n_points, int n_features, int n_clusters, float **feature)
{
    cudaError_t err;

    err = cudaMalloc((void**)&d_feature, n_points * n_features * sizeof(float));
    if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_feature failed\n"); return -1; }

    err = cudaMalloc((void**)&d_feature_swap, n_points * n_features * sizeof(float));
    if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_feature_swap failed\n"); return -1; }

    err = cudaMalloc((void**)&d_cluster, n_clusters * n_features * sizeof(float));
    if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_cluster failed\n"); return -1; }

    err = cudaMalloc((void**)&d_membership, n_points * sizeof(int));
    if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_membership failed\n"); return -1; }

    err = cudaMemcpy(d_feature, feature[0], n_points * n_features * sizeof(float), cudaMemcpyHostToDevice);
    if(err != cudaSuccess) { printf("ERROR: cudaMemcpy d_feature failed\n"); return -1; }

    dim3 block(BLOCK_SIZE);
    dim3 grid((n_points + BLOCK_SIZE - 1) / BLOCK_SIZE);

    kmeans_swap(d_feature, d_feature_swap, n_points, n_features);
    cudaDeviceSynchronize();

    d_membership_OCL = (int*) malloc(n_points * sizeof(int));
    if(!d_membership_OCL) { printf("ERROR: malloc membership_OCL failed\n"); return -1; }

    d_initialized = 1;
    return 0;
}

static int shutdown_cuda()
{
    if(d_initialized) {
        cudaFree(d_feature);
        cudaFree(d_feature_swap);
        cudaFree(d_cluster);
        cudaFree(d_membership);
        free(d_membership_OCL);
        d_initialized = 0;
    }
    return 0;
}

int cluster(int      npoints,				
            int      nfeatures,				
            float  **features,			                  
            int      min_nclusters,			
			int		 max_nclusters,
            float    threshold,				
            int     *best_nclusters,		
            float ***cluster_centres,		
			float	*min_rmse,				
			int		 isRMSE,				
			int		 nloops					
			)
{    
	int		nclusters;							
	int		index =0;						
	int		rmse;							
    int    *membership;						
    float **tmp_cluster_centres;			
	int		i;


    membership = (int*) malloc(npoints * sizeof(int));


	for(nclusters = min_nclusters; nclusters <= max_nclusters; nclusters++)
	{
		if (nclusters > npoints) break;	


		if(initialize_cuda(npoints, nfeatures, nclusters, features)) return -1;


		for(i = 0; i < nloops; i++)
		{

			tmp_cluster_centres = kmeans_clustering(features,
													nfeatures,
													npoints,
													nclusters,
													threshold,
													membership);

			if (*cluster_centres) {
				free((*cluster_centres)[0]);
				free(*cluster_centres);
			}
			*cluster_centres = tmp_cluster_centres;



			if(isRMSE)
			{
				rmse = rms_err(features,
							   nfeatures,
							   npoints,
							   tmp_cluster_centres,
							   nclusters);

				if(rmse < min_rmse_ref){
					min_rmse_ref = rmse;			
					*min_rmse = min_rmse_ref;		
					*best_nclusters = nclusters;	
					index = i;						
				}
			}			
		}

		shutdown_cuda();							
	}

    free(membership);

    return index;
}
